        content: "Aplicăm tot ce am învățat: normalizare, relații, tipuri de date, constrângeri, indecși.\n\nSTUDIU DE CAZ: Sistem de management pentru o librărie online\n\nENTITĂȚI PRINCIPALE:\n- Autori, Cărți, Categorii, Edituri\n- Utilizatori, Adrese\n- Comenzi, Items, Plăți\n- Recenzii, Wishlist\n\nSCHEMA COMPLETĂ:\n```sql\nCREATE DATABASE librarie;\nUSE librarie;\n\nCREATE TABLE autori (\n    id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,\n    prenume VARCHAR(100) NOT NULL,\n    nume VARCHAR(100) NOT NULL,\n    biografie TEXT,\n    INDEX idx_nume (nume)\n);\n\nCREATE TABLE edituri (\n    id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,\n    nume VARCHAR(200) NOT NULL UNIQUE,\n    tara VARCHAR(50)\n);\n\nCREATE TABLE categorii (\n    id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,\n    nume VARCHAR(100) NOT NULL UNIQUE,\n    parinte_id INT UNSIGNED,\n    FOREIGN KEY (parinte_id) REFERENCES categorii(id)\n);\n\nCREATE TABLE carti (\n    id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,\n    isbn VARCHAR(20) UNIQUE NOT NULL,\n    titlu VARCHAR(300) NOT NULL,\n    pret DECIMAL(8,2) NOT NULL CHECK (pret > 0),\n    stoc SMALLINT UNSIGNED DEFAULT 0,\n    categorie_id INT UNSIGNED NOT NULL,\n    editura_id INT UNSIGNED,\n    an_publicare YEAR,\n    FOREIGN KEY (categorie_id) REFERENCES categorii(id),\n    FOREIGN KEY (editura_id) REFERENCES edituri(id) ON DELETE SET NULL,\n    INDEX idx_titlu (titlu),\n    INDEX idx_pret (pret)\n);\n\n-- Many-to-many: o carte poate avea mai mulți autori\nCREATE TABLE carte_autor (\n    carte_id INT UNSIGNED,\n    autor_id INT UNSIGNED,\n    rol ENUM('autor', 'coautor', 'editor', 'translator') DEFAULT 'autor',\n    PRIMARY KEY (carte_id, autor_id),\n    FOREIGN KEY (carte_id) REFERENCES carti(id) ON DELETE CASCADE,\n    FOREIGN KEY (autor_id) REFERENCES autori(id) ON DELETE CASCADE\n);\n```",
